'use client';

import { Link } from '@tanstack/react-router';
import { useLocation, useRouter, useSearch } from '@tanstack/react-router';
import { useCallback, useEffect, useMemo, useRef, useState } from 'react';

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Select,
  SelectContent,
  SelectIcon,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import type { StationSnapshot } from '@/lib/api-types';
import { formatAlertType } from '@/lib/format';
import { appRoutes } from '@/lib/routes';
import { captureExceptionWithContext } from '@/lib/sentry-reporting';
import { fetchJson, useAbortableAsyncEffect } from '@/app/dashboard/_components/useAbortableAsyncEffect';
import { DashboardRouteLinks } from '@/app/dashboard/_components/DashboardRouteLinks';
import { GitHubRepoButton } from '@/app/dashboard/_components/GitHubRepoButton';
import { ThemeToggleButton } from '@/app/dashboard/_components/ThemeToggleButton';
import { PageHeaderCard } from '@/components/layout/page-header-card';
import { PageShell } from '@/components/layout/page-shell';

const PAGE_SIZE = 100;
const DATE_INPUT_PATTERN = /^\d{4}-\d{2}-\d{2}$/;
const ALL_STATIONS_VALUE = '__all_stations__';

type AlertTypeFilter = 'all' | 'LOW_BIKES' | 'LOW_ANCHORS';
type AlertStateFilter = 'all' | 'active' | 'resolved';
type SeverityFilter = 'all' | '1' | '2';

type AlertHistoryRow = {
  id: number;
  stationId: string;
  stationName: string;
  alertType: string;
  severity: number;
  metricValue: number;
  windowHours: number;
  generatedAt: string;
  isActive: boolean;
};

type AlertsHistoryApiResponse = {
  pagination?: {
    total?: number;
    limit?: number;
    offset?: number;
    returned?: number;
  };
  alerts?: AlertHistoryRow[];
};

type AlertsHistoryClientProps = {
  stations: StationSnapshot[];
};

type ViewFilterState = {
  stationId: string;
  alertType: AlertTypeFilter;
  stateFilter: AlertStateFilter;
  severityFilter: SeverityFilter;
  fromDate: string;
  toDate: string;
  page: number;
};

function formatDateTime(value: string): string {
  const parsed = new Date(value);

  if (Number.isNaN(parsed.getTime())) {
    return value;
  }

  return parsed.toLocaleString('es-ES');
}

function parseAlertTypeFilter(value: string | null): AlertTypeFilter {
  if (value === 'LOW_BIKES' || value === 'LOW_ANCHORS') {
    return value;
  }

  return 'all';
}

function parseStateFilter(value: string | null): AlertStateFilter {
  if (value === 'active' || value === 'resolved') {
    return value;
  }

  return 'all';
}

function parseSeverityFilter(value: string | null): SeverityFilter {
  if (value === '1' || value === '2') {
    return value;
  }

  return 'all';
}

function parseDateInput(value: string | null): string {
  if (!value || !DATE_INPUT_PATTERN.test(value)) {
    return '';
  }

  return value;
}

function parsePageIndex(value: string | null): number {
  if (!value) {
    return 0;
  }

  const parsed = Number(value);

  if (!Number.isInteger(parsed) || parsed < 1) {
    return 0;
  }

  return parsed - 1;
}

function toLocalDateInputValue(date: Date): string {
  const adjusted = new Date(date.getTime() - date.getTimezoneOffset() * 60000);
  return adjusted.toISOString().slice(0, 10);
}

function getRangeForLastDays(days: number): { fromDate: string; toDate: string } {
  const end = new Date();
  const start = new Date(end);
  start.setDate(end.getDate() - Math.max(days - 1, 0));

  return {
    fromDate: toLocalDateInputValue(start),
    toDate: toLocalDateInputValue(end),
  };
}

function parseViewStateFromSearchParams(
  params: URLSearchParams,
  stations: StationSnapshot[]
): ViewFilterState {
  const stationIdCandidate = (params.get('stationId') ?? '').trim();
  const hasStation =
    Boolean(stationIdCandidate) &&
    (stations.length === 0 || stations.some((station) => station.id === stationIdCandidate));

  return {
    stationId: hasStation ? stationIdCandidate : '',
    alertType: parseAlertTypeFilter(params.get('alertType')),
    stateFilter: parseStateFilter(params.get('state')),
    severityFilter: parseSeverityFilter(params.get('severity')),
    fromDate: parseDateInput(params.get('from')),
    toDate: parseDateInput(params.get('to')),
    page: parsePageIndex(params.get('page')),
  };
}

function buildViewQueryFromState(state: ViewFilterState): string {
  const params = new URLSearchParams();

  if (state.stationId) {
    params.set('stationId', state.stationId);
  }

  if (state.alertType !== 'all') {
    params.set('alertType', state.alertType);
  }

  if (state.stateFilter !== 'all') {
    params.set('state', state.stateFilter);
  }

  if (state.severityFilter !== 'all') {
    params.set('severity', state.severityFilter);
  }

  if (state.fromDate) {
    params.set('from', state.fromDate);
  }

  if (state.toDate) {
    params.set('to', state.toDate);
  }

  if (state.page > 0) {
    params.set('page', String(state.page + 1));
  }

  return params.toString();
}

export function AlertsHistoryClient({ stations }: AlertsHistoryClientProps) {
  const router = useRouter();
  const location = useLocation();
  const pathname = location.pathname;
  const searchParams = new URLSearchParams((location as { searchStr?: string }).searchStr ?? '');

  const [stationId, setStationId] = useState('');
  const [alertType, setAlertType] = useState<AlertTypeFilter>('all');
  const [stateFilter, setStateFilter] = useState<AlertStateFilter>('all');
  const [severityFilter, setSeverityFilter] = useState<SeverityFilter>('all');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [page, setPage] = useState(0);
  const [isUrlReady, setIsUrlReady] = useState(false);
  const lastSyncedUrlRef = useRef<string | null>(null);
  const prevStationsLengthRef = useRef(-1);
  const [rows, setRows] = useState<AlertHistoryRow[]>([]);
  const [totalRows, setTotalRows] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const apiQueryString = useMemo(() => {
    const params = new URLSearchParams();
    params.set('limit', String(PAGE_SIZE));
    params.set('offset', String(page * PAGE_SIZE));

    if (stationId) {
      params.set('stationId', stationId);
    }

    if (alertType !== 'all') {
      params.set('alertType', alertType);
    }

    if (stateFilter !== 'all') {
      params.set('state', stateFilter);
    }

    if (severityFilter !== 'all') {
      params.set('severity', severityFilter);
    }

    if (fromDate) {
      params.set('from', `${fromDate}T00:00:00.000Z`);
    }

    if (toDate) {
      params.set('to', `${toDate}T23:59:59.999Z`);
    }

    return params.toString();
  }, [alertType, fromDate, page, severityFilter, stateFilter, stationId, toDate]);

  const viewQueryString = useMemo(
    () =>
      buildViewQueryFromState({
        stationId,
        alertType,
        stateFilter,
        severityFilter,
        fromDate,
        toDate,
        page,
      }),
    [alertType, fromDate, page, severityFilter, stateFilter, stationId, toDate]
  );

  useEffect(() => {
    const serialized = searchParams.toString();
    const urlChanged = lastSyncedUrlRef.current === null || serialized !== lastSyncedUrlRef.current;
    const stationsJustHydrated =
      prevStationsLengthRef.current === 0 && stations.length > 0 && !urlChanged;

    if (!urlChanged && !stationsJustHydrated) {
      prevStationsLengthRef.current = stations.length;
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setIsUrlReady(true);
      return;
    }

    const parsedState = parseViewStateFromSearchParams(
      new URLSearchParams(serialized),
      stations
    );

    setStationId(parsedState.stationId);
    setAlertType(parsedState.alertType);
    setStateFilter(parsedState.stateFilter);
    setSeverityFilter(parsedState.severityFilter);
    setFromDate(parsedState.fromDate);
    setToDate(parsedState.toDate);
    setPage(parsedState.page);

    if (urlChanged) {
      lastSyncedUrlRef.current = serialized;
    }
    prevStationsLengthRef.current = stations.length;
    setIsUrlReady(true);
  }, [searchParams, stations]);

  useEffect(() => {
    if (!isUrlReady) {
      return;
    }

    const currentViewQuery = buildViewQueryFromState(
      parseViewStateFromSearchParams(new URLSearchParams(window.location.search), stations)
    );

    if (currentViewQuery === viewQueryString) {
      return;
    }

    const nextUrl = viewQueryString.length > 0 ? `${pathname}?${viewQueryString}` : pathname;
    router.navigate({ to: nextUrl, replace: true });
  }, [isUrlReady, pathname, router, stations, viewQueryString]);

  useAbortableAsyncEffect(
    async (signal, isActive) => {
      try {
        const payload = await fetchJson<AlertsHistoryApiResponse>(
          `${appRoutes.api.alertsHistory()}?${apiQueryString}`,
          {
            signal,
            cache: 'no-store',
            errorMessage: 'No se pudo cargar el historial de alertas.',
          }
        );

        if (!isActive()) {
          return;
        }

        setRows(Array.isArray(payload.alerts) ? payload.alerts : []);
        setTotalRows(Number(payload.pagination?.total ?? 0));
      } catch (error) {
        if (!isActive()) {
          return;
        }

        captureExceptionWithContext(error, {
          area: 'dashboard.alerts-history',
          operation: 'loadHistory',
          extra: {
            query: apiQueryString,
          },
        });
        console.error('[Dashboard] Error cargando historial de alertas.', error);
        setRows([]);
        setTotalRows(0);
        setErrorMessage('No se pudo cargar el historial de alertas.');
      }
    },
    [apiQueryString],
    {
      onStart: () => {
        setIsLoading(true);
        setErrorMessage(null);
      },
      onSettled: () => {
        setIsLoading(false);
      },
    }
  );

  const pageCount = Math.max(1, Math.ceil(totalRows / PAGE_SIZE));
  const hasNextPage = page + 1 < pageCount;
  const hasPreviousPage = page > 0;

  const stats = useMemo(() => {
    const active = rows.filter((row) => row.isActive).length;
    const critical = rows.filter((row) => row.severity >= 2).length;

    return {
      active,
      critical,
    };
  }, [rows]);

  const copyToClipboard = useCallback(() => {
    const headers = ['Fecha', 'Estación', 'ID', 'Tipo', 'Severidad', 'Estado', 'Valor', 'Ventana'];
    const textRows = rows.map((row) => [
      formatDateTime(row.generatedAt),
      row.stationName,
      row.stationId,
      formatAlertType(row.alertType),
      row.severity >= 2 ? 'Crítica' : 'Media',
      row.isActive ? 'Activa' : 'Resuelta',
      row.metricValue.toFixed(1),
      `${row.windowHours}h`,
    ]);
    const text = [headers, ...textRows].map((row) => row.join('\t')).join('\n');
    navigator.clipboard.writeText(text);
  }, [rows]);

  const downloadCsvHref = useMemo(() => {
    const params = new URLSearchParams(apiQueryString);
    params.set('offset', '0');
    params.set('limit', '2000');
    params.set('format', 'csv');
    return `${appRoutes.api.alertsHistory()}?${params.toString()}`;
  }, [apiQueryString]);

  const activeQuickRange = useMemo(() => {
    if (!fromDate || !toDate) {
      return null;
    }

    const today = getRangeForLastDays(1);
    const last7Days = getRangeForLastDays(7);
    const last30Days = getRangeForLastDays(30);

    if (fromDate === today.fromDate && toDate === today.toDate) {
      return 'today';
    }

    if (fromDate === last7Days.fromDate && toDate === last7Days.toDate) {
      return 'last7';
    }

    if (fromDate === last30Days.fromDate && toDate === last30Days.toDate) {
      return 'last30';
    }

    return null;
  }, [fromDate, toDate]);

  const hasActiveFilters =
    stationId.length > 0 ||
    alertType !== 'all' ||
    stateFilter !== 'all' ||
    severityFilter !== 'all' ||
    fromDate.length > 0 ||
    toDate.length > 0 ||
    page > 0;

  const applyQuickRange = (days: number) => {
    const range = getRangeForLastDays(days);
    setFromDate(range.fromDate);
    setToDate(range.toDate);
    setPage(0);
  };

  const clearFilters = () => {
    setStationId('');
    setAlertType('all');
    setStateFilter('all');
    setSeverityFilter('all');
    setFromDate('');
    setToDate('');
    setPage(0);
  };

  return (
    <PageShell>
      <PageHeaderCard>
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-3 text-[var(--primary)]">
              <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-[var(--primary)] text-sm font-black text-white">
                B
              </div>
              <h1 className="text-lg font-bold text-[var(--foreground)]">Historial de alertas</h1>
            </div>
            <DashboardRouteLinks
              routes={['dashboard', 'stations', 'flow', 'conclusions', 'help']}
              variant="inline"
              className="hidden items-center gap-5 md:flex"
            />
          </div>

          <div className="flex flex-wrap items-center justify-end gap-2">
            <DashboardRouteLinks
              routes={['dashboard', 'stations', 'flow', 'conclusions', 'help']}
              variant="chips"
              className="flex flex-wrap items-center gap-2 md:hidden"
            />
            <Link to={appRoutes.dashboard()} className="ui-icon-button" aria-label="Volver al dashboard">
              Inicio
            </Link>
            <ThemeToggleButton />
            <GitHubRepoButton />
          </div>
        </div>

        <div className="mt-3 grid gap-2 md:grid-cols-2 xl:grid-cols-6">
          <Select
            value={stationId || ALL_STATIONS_VALUE}
            onValueChange={(value) => {
              setStationId(!value || value === ALL_STATIONS_VALUE ? '' : value);
              setPage(0);
            }}
          >
            <SelectTrigger aria-label="Filtrar por estación" className="w-full bg-[var(--secondary)]">
              <SelectValue />
              <SelectIcon />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value={ALL_STATIONS_VALUE}>Todas las estaciones</SelectItem>
              {stations.map((station) => (
                <SelectItem key={station.id} value={station.id}>
                  {station.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>

          <Select
            value={alertType}
            onValueChange={(value) => {
              setAlertType((value as AlertTypeFilter) ?? 'all');
              setPage(0);
            }}
          >
            <SelectTrigger aria-label="Filtrar por tipo de alerta" className="w-full bg-[var(--secondary)]">
              <SelectValue />
              <SelectIcon />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos los tipos</SelectItem>
              <SelectItem value="LOW_BIKES">Pocas bicis</SelectItem>
              <SelectItem value="LOW_ANCHORS">Pocos anclajes</SelectItem>
            </SelectContent>
          </Select>

          <Select
            value={stateFilter}
            onValueChange={(value) => {
              setStateFilter((value as AlertStateFilter) ?? 'all');
              setPage(0);
            }}
          >
            <SelectTrigger aria-label="Filtrar por estado" className="w-full bg-[var(--secondary)]">
              <SelectValue />
              <SelectIcon />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todos los estados</SelectItem>
              <SelectItem value="active">Activas</SelectItem>
              <SelectItem value="resolved">Resueltas</SelectItem>
            </SelectContent>
          </Select>

          <Select
            value={severityFilter}
            onValueChange={(value) => {
              setSeverityFilter((value as SeverityFilter) ?? 'all');
              setPage(0);
            }}
          >
            <SelectTrigger aria-label="Filtrar por severidad" className="w-full bg-[var(--secondary)]">
              <SelectValue />
              <SelectIcon />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">Todas las severidades</SelectItem>
              <SelectItem value="1">Media</SelectItem>
              <SelectItem value="2">Critica</SelectItem>
            </SelectContent>
          </Select>

          <Input
            type="date"
            value={fromDate}
            onChange={(event) => {
              setFromDate(event.target.value);
              setPage(0);
            }}
            aria-label="Fecha desde"
            className="bg-[var(--secondary)]"
          />

          <Input
            type="date"
            value={toDate}
            onChange={(event) => {
              setToDate(event.target.value);
              setPage(0);
            }}
            aria-label="Fecha hasta"
            className="bg-[var(--secondary)]"
          />
        </div>

        <div className="mt-3 flex flex-wrap items-center gap-2">
          <span className="text-xs font-semibold uppercase tracking-[0.12em] text-[var(--muted)]">
            Rangos rapidos
          </span>
          <Button
            onClick={() => applyQuickRange(1)}
            variant={activeQuickRange === 'today' ? 'default' : 'outline'}
            size="sm"
            className={`rounded-full px-3 py-1 text-xs ${
              activeQuickRange === 'today'
                ? 'border-[var(--primary)]'
                : 'hover:border-[var(--primary)]'
            }`}
          >
            Hoy
          </Button>
          <Button
            onClick={() => applyQuickRange(7)}
            variant={activeQuickRange === 'last7' ? 'default' : 'outline'}
            size="sm"
            className={`rounded-full px-3 py-1 text-xs ${
              activeQuickRange === 'last7'
                ? 'border-[var(--primary)]'
                : 'hover:border-[var(--primary)]'
            }`}
          >
            7 dias
          </Button>
          <Button
            onClick={() => applyQuickRange(30)}
            variant={activeQuickRange === 'last30' ? 'default' : 'outline'}
            size="sm"
            className={`rounded-full px-3 py-1 text-xs ${
              activeQuickRange === 'last30'
                ? 'border-[var(--primary)]'
                : 'hover:border-[var(--primary)]'
            }`}
          >
            30 dias
          </Button>
          <Button
            onClick={clearFilters}
            disabled={!hasActiveFilters}
            variant="outline"
            size="sm"
            className="rounded-full px-3 py-1 text-xs hover:border-[var(--primary)]"
          >
            Limpiar filtros
          </Button>

          <span className="ml-auto text-xs text-[var(--muted)]">La URL refleja los filtros actuales.</span>
        </div>
      </PageHeaderCard>

      <section className="grid gap-4 md:grid-cols-2 xl:grid-cols-4">
        <Card className="ui-section-card">
          <p className="stat-label">Total filtrado</p>
          <p className="stat-value">{totalRows}</p>
        </Card>
        <Card className="ui-section-card">
          <p className="stat-label">Activas (pagina)</p>
          <p className="stat-value">{stats.active}</p>
        </Card>
        <Card className="ui-section-card">
          <p className="stat-label">Criticas (pagina)</p>
          <p className="stat-value">{stats.critical}</p>
        </Card>
        <Card className="ui-section-card">
          <p className="stat-label">Exportar</p>
          <div className="flex flex-wrap gap-2">
            <Button
              onClick={copyToClipboard}
              disabled={rows.length === 0}
              variant="outline"
              size="sm"
              className="px-3 py-2 text-xs"
            >
              Copiar
            </Button>
            <a
              href={downloadCsvHref}
              className="inline-flex rounded-lg border border-[var(--primary)] px-3 py-2 text-xs font-bold text-[var(--primary)] transition hover:bg-[var(--primary)] hover:text-white"
            >
              CSV
            </a>
          </div>
        </Card>
      </section>

      <section className="overflow-hidden rounded-xl border border-[var(--border)] bg-[var(--card)] shadow-[var(--shadow-soft)]">
        <header className="flex flex-wrap items-center justify-between gap-2 border-b border-[var(--border)] bg-[var(--secondary)] px-4 py-3">
          <p className="text-sm font-semibold text-[var(--foreground)]">Registros de alertas</p>
          <p className="text-xs text-[var(--muted)]">
            Pagina {page + 1}/{pageCount} · {rows.length} filas
          </p>
        </header>

        {isLoading ? (
          <p className="px-4 py-6 text-sm text-[var(--muted)]">Cargando historial...</p>
        ) : errorMessage ? (
          <p className="px-4 py-6 text-sm text-[var(--muted)]">{errorMessage}</p>
        ) : rows.length === 0 ? (
          <p className="px-4 py-6 text-sm text-[var(--muted)]">No hay alertas para los filtros actuales.</p>
        ) : (
          <ScrollArea className="overflow-x-auto max-h-[600px]">
            <Table className="min-w-full border-collapse text-sm">
              <TableHeader className="sticky top-0 z-10 bg-[var(--secondary)]">
                <TableRow className="text-left text-xs uppercase tracking-[0.12em] text-[var(--muted)]">
                  <TableHead className="h-auto px-4 py-3">Fecha</TableHead>
                  <TableHead className="h-auto px-4 py-3">Estacion</TableHead>
                  <TableHead className="h-auto px-4 py-3">Tipo</TableHead>
                  <TableHead className="h-auto px-4 py-3">Severidad</TableHead>
                  <TableHead className="h-auto px-4 py-3">Estado</TableHead>
                  <TableHead className="h-auto px-4 py-3">Valor</TableHead>
                  <TableHead className="h-auto px-4 py-3">Ventana</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {rows.map((row) => (
                  <TableRow key={row.id} className="border-t border-[var(--border)] text-[var(--foreground)]">
                    <TableCell className="whitespace-nowrap px-4 py-3 text-xs text-[var(--muted)]">
                      {formatDateTime(row.generatedAt)}
                    </TableCell>
                    <TableCell className="px-4 py-3">
                      <p className="font-semibold">{row.stationName}</p>
                      <p className="text-xs text-[var(--muted)]">{row.stationId}</p>
                    </TableCell>
                    <TableCell className="whitespace-nowrap px-4 py-3">{formatAlertType(row.alertType)}</TableCell>
                    <TableCell className="px-4 py-3">
                      <Badge variant={row.severity >= 2 ? 'danger' : 'warning'}>
                        {row.severity >= 2 ? 'Critica' : 'Media'}
                      </Badge>
                    </TableCell>
                    <TableCell className="px-4 py-3">
                      <Badge variant={row.isActive ? 'success' : 'muted'}>
                        {row.isActive ? 'Activa' : 'Resuelta'}
                      </Badge>
                    </TableCell>
                    <TableCell className="whitespace-nowrap px-4 py-3 text-xs">{row.metricValue.toFixed(1)}</TableCell>
                    <TableCell className="whitespace-nowrap px-4 py-3 text-xs text-[var(--muted)]">
                      {row.windowHours}h
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </ScrollArea>
        )}

        <footer className="flex items-center justify-between gap-2 border-t border-[var(--border)] bg-[var(--secondary)] px-4 py-3">
          <p className="text-xs text-[var(--muted)]">Muestra de {PAGE_SIZE} filas por pagina</p>
          <div className="flex items-center gap-2">
            <Button
              onClick={() => hasPreviousPage && setPage((current) => current - 1)}
              disabled={!hasPreviousPage || isLoading}
              variant="outline"
              size="sm"
              className="text-xs"
            >
              Anterior
            </Button>
            <Button
              onClick={() => hasNextPage && setPage((current) => current + 1)}
              disabled={!hasNextPage || isLoading}
              variant="outline"
              size="sm"
              className="text-xs"
            >
              Siguiente
            </Button>
          </div>
        </footer>
      </section>
    </PageShell>
  );
}
